MOD_ADLER = 65521

def adler32(text):
    a = 1
    b = 0
    for char in text:
        a = (a + ord(char)) % MOD_ADLER
        b = (b + a) % MOD_ADLER
    return (b << 16) | a

if __name__ == "__main__":
    print(f"Checksum: {adler32('Algorithms')}")

